  1→import { QUAD_VS, QUAD_FS, TILED_FS, ELLIPSE_FS } from './shaders';
  2→
  3→function compileShader(gl: WebGL2RenderingContext, type: number, src: string): WebGLShader | null {
  4→  const s = gl.createShader(type)!;
  5→  gl.shaderSource(s, src);
  6→  gl.compileShader(s);
  7→  if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
  8→    console.error('Shader:', gl.getShaderInfoLog(s));
  9→    gl.deleteShader(s);
 10→    return null;
 11→  }
 12→  return s;
 13→}
 14→
 15→function createProgram(gl: WebGL2RenderingContext, vsSrc: string, fsSrc: string): WebGLProgram | null {
 16→  const vs = compileShader(gl, gl.VERTEX_SHADER, vsSrc);
 17→  const fs = compileShader(gl, gl.FRAGMENT_SHADER, fsSrc);
 18→  if (!vs || !fs) return null;
 19→  const p = gl.createProgram()!;
 20→  gl.attachShader(p, vs);
 21→  gl.attachShader(p, fs);
 22→  gl.linkProgram(p);
 23→  if (!gl.getProgramParameter(p, gl.LINK_STATUS)) {
 24→    console.error('Program:', gl.getProgramInfoLog(p));
 25→    return null;
 26→  }
 27→  return p;
 28→}
 29→
 30→export interface ProgramLocs {
 31→  resolution: WebGLUniformLocation | null;
 32→  tex: WebGLUniformLocation | null;
 33→  alphaMode: WebGLUniformLocation | null;
 34→}
 35→
 36→export interface TiledLocs extends ProgramLocs {
 37→  quadSize: WebGLUniformLocation | null;
 38→  tileSize: WebGLUniformLocation | null;
 39→}
 40→
 41→export interface EllipseLocs {
 42→  resolution: WebGLUniformLocation | null;
 43→  tex: WebGLUniformLocation | null;
 44→  ellipseCenter: WebGLUniformLocation | null;
 45→  ellipseRadius: WebGLUniformLocation | null;
 46→  uvOffset: WebGLUniformLocation | null;
 47→}
 48→
 49→export class GLContext {
 50→  gl!: WebGL2RenderingContext;
 51→  canvas!: HTMLCanvasElement;
 52→  canvasW = 0;
 53→  canvasH = 0;
 54→  dpr = 1;
 55→
 56→  quadProg!: WebGLProgram;
 57→  tiledProg!: WebGLProgram;
 58→  ellipseProg!: WebGLProgram;
 59→
 60→  quadLocs!: ProgramLocs;
 61→  tiledLocs!: TiledLocs;
 62→  ellipseLocs!: EllipseLocs;
 63→
 64→  private resizeHandler = () => this.resize();
 65→
 66→  init(canvas: HTMLCanvasElement) {
 67→    this.canvas = canvas;
 68→    this.gl = canvas.getContext('webgl2', {
 69→      alpha: true,
 70→      premultipliedAlpha: false,
 71→      antialias: false,
 72→      depth: false,
 73→      stencil: true,
 74→    })!;
 75→
 76→    const gl = this.gl;
 77→
 78→    this.quadProg = createProgram(gl, QUAD_VS, QUAD_FS)!;
 79→    this.tiledProg = createProgram(gl, QUAD_VS, TILED_FS)!;
 80→    this.ellipseProg = createProgram(gl, QUAD_VS, ELLIPSE_FS)!;
 81→
 82→    this.quadLocs = {
 83→      resolution: gl.getUniformLocation(this.quadProg, 'u_resolution'),
 84→      tex: gl.getUniformLocation(this.quadProg, 'u_tex'),
 85→      alphaMode: gl.getUniformLocation(this.quadProg, 'u_alphaMode'),
 86→    };
 87→    this.tiledLocs = {
 88→      resolution: gl.getUniformLocation(this.tiledProg, 'u_resolution'),
 89→      tex: gl.getUniformLocation(this.tiledProg, 'u_tex'),
 90→      quadSize: gl.getUniformLocation(this.tiledProg, 'u_quadSize'),
 91→      tileSize: gl.getUniformLocation(this.tiledProg, 'u_tileSize'),
 92→      alphaMode: gl.getUniformLocation(this.tiledProg, 'u_alphaMode'),
 93→    };
 94→    this.ellipseLocs = {
 95→      resolution: gl.getUniformLocation(this.ellipseProg, 'u_resolution'),
 96→      tex: gl.getUniformLocation(this.ellipseProg, 'u_tex'),
 97→      ellipseCenter: gl.getUniformLocation(this.ellipseProg, 'u_ellipseCenter'),
 98→      ellipseRadius: gl.getUniformLocation(this.ellipseProg, 'u_ellipseRadius'),
 99→      uvOffset: gl.getUniformLocation(this.ellipseProg, 'u_uvOffset'),
100→    };
101→
102→    this.resize();
103→    window.addEventListener('resize', this.resizeHandler);
104→  }
105→
106→  resize() {
107→    this.dpr = window.devicePixelRatio || 1;
108→    this.canvasW = window.innerWidth;
109→    this.canvasH = window.innerHeight;
110→    this.canvas.width = this.canvasW * this.dpr;
111→    this.canvas.height = this.canvasH * this.dpr;
112→    this.canvas.style.width = this.canvasW + 'px';
113→    this.canvas.style.height = this.canvasH + 'px';
114→    this.gl.viewport(0, 0, this.canvas.width, this.canvas.height);
115→  }
116→
117→  destroy() {
118→    window.removeEventListener('resize', this.resizeHandler);
119→  }
120→}
